1	type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	};
7	type QuoteStep = { op: "quote"; items: Item[] };
8	type ClaimStep = {
9	  op: "claim";
10	  policy: number;
11	  incident: {
12	    cause: string;
13	    damages: { itemType: string; amount: number }[];
14	  };
15	};
16	type Step = QuoteStep | ClaimStep;
17	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
18	
19	const FIRST_INSURANCE_MULTIPLIER = 1.1;
20	const POST_FIRST_CONTRACT_MULTIPLIER = 0.85;
21	const CURSED_MULTIPLIER = 1.5;
22	const HIGH_ENCHANTMENT_PREMIUM_THRESHOLD = 5;
23	const HIGH_ENCHANTMENT_PREMIUM_MULTIPLIER = 1.3;
24	const LOYALTY_MULTIPLIER = 0.8;
25	const LOYALTY_YEARS_THRESHOLD = 2;
26	const ADMIN_FEE = 5;
27	const DEDUCTIBLE = 100;
28	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
29	const HIGH_ENCHANTMENT_REIMBURSEMENT_FRACTION = 0.5;
30	
31	// Three alike pieces of a "building-block" item (rune, moonstone, …) pool
32	// to a single unit priced at this fixed tier, irrespective of the per-piece
33	// BASE_PRICE. The tier coincidentally equals amulet's base price today but
34	// is conceptually a separate pricing rule from the per-item ladder.
35	const BUILDING_BLOCK_PRICE = 60;
36	
37	const BASE_PRICE: Record<string, number> = {
38	  sword: 100,
39	  staff: 80,
40	  amulet: 60,
41	  potion: 40,
42	  rune: 25,
43	  moonstone: 25,
44	};
45	
46	const POOLED_TYPES = new Set(["rune", "moonstone"]);
47	
48	function itemModifierMultiplier(item: Item): number {
49	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
50	  const highEnchantment =
51	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PREMIUM_THRESHOLD
52	      ? HIGH_ENCHANTMENT_PREMIUM_MULTIPLIER
53	      : 1;
54	  return cursed * highEnchantment;
55	}
56	
57	// MHPCO always rounds the euro value of a discounted/loaded price upward
58	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
59	// values that are mathematically integer (e.g. 100 × 1.10 = 110) don't get
60	// bumped up a euro by a 110.00000000000001 representation.
61	function ceilInMhpcoFavor(value: number): number {
62	  return Math.ceil(Number(value.toFixed(10)));
63	}
64	
65	// Sum of per-item base prices (with item-attribute multipliers applied)
66	// for a single quote. Building-block items (rune today, moonstone in cycle
67	// 13) are pooled in groups of three at BUILDING_BLOCK_PRICE; leftovers fall
68	// back to the per-piece BASE_PRICE.
69	function quoteItemsSubtotal(items: Item[]): number {
70	  let subtotal = 0;
71	  const pooledCounts = new Map<string, number>();
72	  for (const item of items) {
73	    if (POOLED_TYPES.has(item.type)) {
74	      pooledCounts.set(item.type, (pooledCounts.get(item.type) ?? 0) + 1);
75	    } else {
76	      subtotal += BASE_PRICE[item.type] * itemModifierMultiplier(item);
77	    }
78	  }
79	  for (const [type, count] of pooledCounts) {
80	    const buildingBlocks = Math.floor(count / 3);
81	    const loose = count % 3;
82	    subtotal += buildingBlocks * BUILDING_BLOCK_PRICE + loose * BASE_PRICE[type];
83	  }
84	  return subtotal;
85	}
86	
87	// Reimbursement percentage by item attribute (dragon material always wins
88	// today; enchantment 9 and other tiers will join here in later cycles).
89	function itemReimbursementFraction(item: Item | undefined): number {
90	  if (item?.material === "dragon") return 1;
91	  if ((item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD)
92	    return HIGH_ENCHANTMENT_REIMBURSEMENT_FRACTION;
93	  return 0;
94	}
95	
96	// Look up the insured item on the originating quote (referenced by
97	// `claimStep.policy` as an index into the step list), compute the
98	// reimbursement for the incident, subtract the flat deductible, and floor
99	// the payout at zero.
100	function claimPayout(claimStep: ClaimStep, allSteps: Step[]): { payout: number } {
101	  const policyStep = allSteps[claimStep.policy] as QuoteStep;
102	  const reimbursement = claimStep.incident.damages.reduce((sum, damage) => {
103	    const item = policyStep.items.find((quotedItem) => quotedItem.type === damage.itemType);
104	    return sum + damage.amount * itemReimbursementFraction(item);
105	  }, 0);
106	  return { payout: Math.max(0, reimbursement - DEDUCTIBLE) };
107	}
108	
109	export function runScenario(scenario: unknown): unknown {
110	  const { customer, steps } = scenario as Scenario;
111	  const loyaltyMultiplier =
112	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_MULTIPLIER : 1;
113	  const results = steps.map((step, quoteIndex) => {
114	    if (step.op === "claim") return claimPayout(step, steps);
115	    const itemsSubtotal = quoteItemsSubtotal(step.items);
116	    const contractMultiplier =
117	      quoteIndex === 0 ? FIRST_INSURANCE_MULTIPLIER : POST_FIRST_CONTRACT_MULTIPLIER;
118	    const premium =
119	      ceilInMhpcoFavor(itemsSubtotal * loyaltyMultiplier * contractMultiplier) +
120	      ADMIN_FEE;
121	    return { premium };
122	  });
123	  return { results };
124	}
